function Dashboard(p:any){return <div className="dashboard-screen relative -m-6 min-h-screen overflow-hidden bg-[#181818] px-5 py-8 text-white sm:px-8 md:px-12 md:py-10 lg:-m-9 lg:px-12 lg:py-12 2xl:px-16"><div className="pointer-events-none absolute left-1/2 top-[-120px] h-[420px] w-[min(620px,80vw)] -translate-x-1/2 rounded-full bg-primary/[.055] blur-3xl"/><div className="pointer-events-none absolute bottom-10 right-4 h-56 w-56 rounded-full bg-primary/[.04] blur-3xl md:right-10"/><div className="relative mx-auto flex min-h-[calc(100vh-80px)] w-full max-w-[1120px] flex-col items-center justify-center"><div className="mb-6 w-full text-center md:mb-8"><span className="rounded-full border border-white/10 bg-white/[.06] px-3 py-1 text-xs font-black uppercase tracking-[.18em] text-primary">AI Intelligence Workspace</span><h1 className="mx-auto mt-5 max-w-[1000px] text-[40px] font-black leading-[1.04] tracking-[-.03em]">Good evening, Fatima.<br/><span className="text-white/78">What would you like Veralyze to investigate?</span></h1><p className="mx-auto mt-4 max-w-[760px] text-[clamp(.95rem,1.6vw,1.08rem)] leading-7 text-white/50">Paste any YouTube video to uncover hidden claims, source credibility, manipulation signals, and risk.</p></div><div className="flex w-full justify-center"><div className="w-full max-w-[860px]"><DarkUrlRun {...p}/><div className="mt-4 flex flex-wrap justify-center gap-2 max-sm:justify-stretch">{[['Try sample video',()=>{}],['Open last report',()=>p.setActive('Analysis Report')],['View history',()=>p.setActive('History')]].map(([label,fn]:any)=><button key={label} onClick={fn} className="rounded-full border border-white/10 bg-white/[.05] px-4 py-2 text-sm font-bold text-white/60 transition hover:border-primary/40 hover:text-white max-sm:flex-1">{label}</button>)}</div></div></div><Card className="mt-6 w-full max-w-[860px] border-white/10 bg-white/[.055] p-4 text-white backdrop-blur"><div className="flex items-center justify-between gap-4 max-sm:block"><div className="min-w-0"><p className="text-xs font-black uppercase tracking-[.14em] text-white/35">Recent Analysis</p><h3 className="mt-1 truncate font-black max-sm:whitespace-normal">{p.reports[0]?.title || 'No recent analysis yet'}</h3>{p.reports[0]&&<p className="mt-1 text-sm text-white/45"><Badge>{p.reports[0].risk}</Badge> <span className="ml-2">{p.reports[0].trust}/100 trust</span></p>}</div><button onClick={()=>p.setActive(p.reports[0]?'Analysis Report':'Analyze')} className="shrink-0 rounded-xl border border-white/10 px-3 py-2 text-sm font-black text-white/70 transition hover:bg-white/[.06] hover:text-white max-sm:mt-4 max-sm:w-full">{p.reports[0]?'Open Report':'Start Scan'} →</button></div></Card></div></div>}
function Analyze(p:any){const[open,setOpen]=useState(false);const avg=Math.round(p.reports.reduce((a:any,b:any)=>a+b.trust,0)/Math.max(1,p.reports.length));return <div className="relative"><div className="pointer-events-none absolute right-[-80px] top-[-80px] h-64 w-64 rounded-full bg-primary/[.045] blur-3xl"/><Title title="Analyze" sub="Your workspace for running analyses, reviewing activity, and reopening reports."/><div className="mb-6 grid gap-5 xl:grid-cols-[1fr_340px]"><div className="relative"><div className="pointer-events-none absolute inset-x-10 top-10 -z-0 h-32 rounded-full bg-primary/[.10] blur-3xl"/><Card className="relative z-10 p-7"><h2 className="text-2xl font-black">Run a new analysis</h2><p className="mt-1 text-white/45">Paste a YouTube URL or use an example to start the AI workflow.</p><div className="mt-5"><DarkUrlRun {...p}/></div><div className="mt-3 flex flex-wrap gap-2">{['Finance claim','Health advice','Policy risk'].map(x=><button className="rounded-full border border-white/10 bg-white/[.04] px-3 py-1.5 text-sm font-bold text-white/60 hover:border-primary/40 hover:bg-white/[.07] hover:text-white" key={x}>Example: {x}</button>)}</div></Card></div><div className="relative"><div className="pointer-events-none absolute inset-x-8 top-8 -z-0 h-24 rounded-full bg-primary/[.08] blur-3xl"/><Card className="relative z-10 p-5"><b>Activity overview</b><div className="mt-4 grid gap-3">{[['Reports',p.reports.length],['Average trust',avg+'%'],['High risk',p.reports.filter((r:Report)=>['High','Critical'].includes(r.risk)).length]].map(([a,b]:any)=><button onClick={()=>p.setActive('History')} className="flex items-center justify-between rounded-xl border border-white/10 bg-black/20 p-3 font-bold text-white/80 transition hover:border-primary/30 hover:bg-primary/[.08]" key={a}><span>{a}</span><span>{b}</span></button>)}</div></Card></div></div><div className="mb-6 grid gap-4 md:grid-cols-4">{[["Total Analyses",p.reports.length,BarChart3],["Saved Reports",p.reports.filter((r:Report)=>r.saved).length,Save],["Avg Trust",avg+'%',Gauge],["High Risk",p.reports.filter((r:Report)=>['High','Critical'].includes(r.risk)).length,AlertTriangle]].map(([a,b,I]:any)=><Card key={a} onClick={()=>p.setActive('History')} className="p-5"><div className="flex justify-between"><div><p className="text-sm font-bold text-white/45">{a}</p><p className="mt-2 text-3xl font-black">{b}</p></div><div className="grid size-10 place-items-center rounded-xl bg-black/20"><I size={18}/></div></div></Card>)}</div><div className="mb-6 grid gap-5 xl:grid-cols-[1fr_320px]"><ReportList rows={p.reports.slice(0,5)} setActive={p.setActive}/><div className="grid gap-5"><Card className="p-5"><b>Saved Reports</b>{p.reports.filter((r:Report)=>r.saved).length?<p className="mt-2 text-sm text-white/45">Saved report previews appear here.</p>:<div className="mt-4 rounded-2xl border border-white/10 bg-black/20 p-5 text-center"><Save className="mx-auto text-white/35"/><b className="mt-2 block">No saved reports</b><Button variant="tertiary" onClick={()=>p.setActive('History')}>Browse reports <ArrowRight size={14}/></Button></div>}</Card><Card className="p-5"><b>Analysis insights</b><p className="mt-3 text-sm text-white/45">Most recent reports show elevated risk around unsupported financial and environmental claims.</p><button onClick={()=>setOpen(!open)} className="mt-4 flex w-full justify-between rounded-xl border border-white/10 bg-black/20 px-3 py-2 font-bold hover:bg-white/[.06]">What Veralyze checks <ChevronDown className={open?'rotate-180':''}/></button>{open&&<div className="mt-3 grid gap-2">{['Claims','Sources','Risk Signals','Recommendations','Manipulation','Missing Context','Contradictions','Next Steps'].map(x=><div className="rounded-xl border border-white/10 bg-black/20 p-2 text-sm font-bold" key={x}>{x}</div>)}</div>}</Card></div></div></div>}
function HistoryPage({reports,setActive}:{reports:Report[];setActive:(p:Page)=>void}){const[q,setQ]=useState(''),[risk,setRisk]=useState('All Risk'),[cat,setCat]=useState('All Categories'),[sort,setSort]=useState('Newest'),[sk,setSk]=useState(true);useEffect(()=>{setTimeout(()=>setSk(false),500)},[]);const rows=useMemo(()=>{let r=reports.filter(x=>(risk==='All Risk'||x.risk===risk)&&(cat==='All Categories'||x.category===cat)&&x.title.toLowerCase().includes(q.toLowerCase()));if(sort.includes('High'))r=[...r].sort((a,b)=>b.trust-a.trust);if(sort.includes('Low'))r=[...r].sort((a,b)=>a.trust-b.trust);return r},[q,risk,cat,sort,reports]);return <div className="relative"><div className="pointer-events-none absolute left-[-60px] top-10 h-56 w-56 rounded-full bg-primary/[.055] blur-3xl"/><Title title="Analysis History" sub="Search, filter, and reopen intelligence reports."/><GlowWrap className="mb-4" glow="bg-primary/[.07]"><div className="grid gap-3 lg:grid-cols-[1fr_160px_180px_210px]"><div className="relative"><Search className="absolute left-4 top-3.5 text-white/35" size={18}/><input value={q} onChange={e=>setQ(e.target.value)} className="h-12 w-full rounded-xl border border-white/10 bg-white/[.06] text-white pl-11 outline-none focus:ring-4 focus:ring-primary/25" placeholder="Search reports..."/></div>{[[risk,setRisk,['All Risk','Critical','High','Medium','Low']],[cat,setCat,['All Categories','Science','Technology','Environment','Politics']],[sort,setSort,['Newest','Oldest','Trust Score High to Low','Trust Score Low to High']]].map(([v,set,items]:any,i)=><select key={i} value={v} onChange={e=>set(e.target.value)} className="h-12 rounded-xl border border-white/10 bg-white/[.06] text-white px-3 font-bold">{items.map((x:string)=><option key={x}>{x}</option>)}</select>)}</div></GlowWrap>{sk?<div className="grid gap-3"><Skeleton/><Skeleton/><Skeleton/></div>:<GlowWrap glow="bg-primary/[.09]"><ReportList rows={rows} setActive={setActive}/></GlowWrap>}</div>}
function Report({toast}:{toast:(m:string,t?:string)=>void}){const[sk,setSk]=useState(true);useEffect(()=>{setTimeout(()=>setSk(false),500)},[]);const navItems=[['summary','Summary'],['claims','Claims'],['context','Context'],['techniques','Tactics'],['sources','Sources'],['timeline','Timeline']];const claims=[['Revenue claim inflated by timeframe compression','Presenter frames a 30-day gain without showing ad spend, refund rates, taxes, or sample size.','High risk',27,83],['Expert endorsement lacks source trail','A named analyst is cited, but no publication, institution, or dated source appears in transcript.','Unverified',38,76],['Tool outcome presented as guaranteed','Conditional workflow is described as repeatable income, while disclaimers are pushed to the final minute.','Manipulative',22,88]];const tactics=[['Urgency pressure','“Before this gets taken down” appears 4 times across CTA segments.',78],['Authority borrowing','References institutions without URLs or visible citations.',64],['Selective proof','Screenshots shown, no ledger-level evidence or independent audit.',82]];const sources=[['FTC business opportunity guidance','Contradicts income guarantee framing','Strong'],['YouTube transcript evidence','Confirms repeated scarcity language','Direct'],['Creator-linked sales page','Commercial conflict disclosed late','Weak']];const timeline=[['00:18','Hook','High-income promise introduced before method details.'],['03:42','Proof segment','Revenue screenshot shown without cost basis.'],['08:16','Source gap','External expert mentioned with no source trail.'],['12:04','CTA','Scarcity and limited-window framing intensifies.']];return <div className="relative"><div className="pointer-events-none absolute right-0 top-8 h-72 w-72 rounded-full bg-primary/[.065] blur-3xl"/><Title title="Analysis Report" sub="Premium intelligence brief · Manipulation analysis · Technology" action={<Button onClick={()=>toast('Report saved')}><Save size={16}/> Save Report</Button>}/><div className="grid gap-6 xl:grid-cols-[1fr_360px]"><div className="min-w-0 space-y-6"><nav className="sticky top-20 z-20 -mx-1 flex gap-2 overflow-x-auto rounded-2xl border border-white/10 bg-[#181818]/80 p-2 shadow-[0_18px_50px_rgba(0,0,0,.28)] backdrop-blur-xl">{navItems.map(([id,label])=><a key={id} href={`#${id}`} className="shrink-0 rounded-xl px-3 py-2 text-sm font-black text-white/55 transition hover:bg-white/[.06] hover:text-white focus:bg-primary focus:text-[#181818]">{label}</a>)}</nav><GlowWrap glow="bg-primary/[.08]"><Card id="summary" className="overflow-hidden p-0"><div className="grid lg:grid-cols-[300px_1fr]"><div className="relative grid min-h-64 place-items-center overflow-hidden bg-[#111]"><div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_35%,rgba(231,255,71,.16),transparent_42%)]"/><Play className="relative z-10 text-primary drop-shadow-[0_0_22px_rgba(231,255,71,.35)]" fill="#E7FF47" size={46}/><div className="absolute bottom-4 left-4 right-4 rounded-2xl border border-white/10 bg-black/45 p-3 text-xs font-bold text-white/55 backdrop-blur">youtube.com/watch?v=... · 18:42 runtime</div></div><div className="p-7"><div className="flex flex-wrap gap-2"><Badge>High</Badge><span className="rounded-full border border-white/10 bg-white/[.06] px-3 py-1 text-xs font-black text-white/60">84% model confidence</span><span className="rounded-full border border-primary/20 bg-primary/[.08] px-3 py-1 text-xs font-black text-primary">3 critical claims</span></div><h2 className="mt-5 text-[34px] font-black leading-tight tracking-[-.01em]">AI credibility report</h2><p className="mt-3 max-w-2xl text-lg leading-8 text-white/60">The video relies on compressed proof, scarcity framing, and weak source attribution. Treat revenue and repeatability claims as unsupported until independent evidence is provided.</p><div className="mt-6 grid gap-3 md:grid-cols-3">{[['Claims extracted','9'],['Evidence items','14'],['Risk signals','7']].map(([a,b])=><div key={a} className="rounded-2xl border border-white/10 bg-black/20 p-4"><p className="text-xs font-black uppercase tracking-[.14em] text-white/35">{a}</p><b className="mt-2 block text-2xl">{b}</b></div>)}</div></div></div></Card></GlowWrap>{sk?<><Skeleton/><Skeleton/><Skeleton/></>:<><section id="claims" className="scroll-mt-28"><div className="mb-3 flex items-end justify-between"><div><h2 className="text-2xl font-black">Key claims requiring scrutiny</h2><p className="text-white/45">Prioritized by risk, confidence, and evidence quality.</p></div><FileText className="text-primary"/></div><div className="grid gap-4">{claims.map(([title,body,status,trust,conf]:any,i)=><Card key={title} className="p-5"><div className="flex gap-4 max-md:block"><div className="grid size-11 shrink-0 place-items-center rounded-2xl bg-primary text-[#181818] font-black">{i+1}</div><div className="min-w-0 flex-1"><div className="flex flex-wrap items-start justify-between gap-3"><h3 className="text-xl font-black">{title}</h3><span className="rounded-full border border-white/10 bg-white/[.06] px-3 py-1 text-xs font-black text-white/65">{status}</span></div><p className="mt-2 text-white/58">{body}</p><div className="mt-4 flex flex-wrap gap-2">{['Transcript match','Missing citation','Commercial CTA'].map(x=><span key={x} className="rounded-full border border-white/10 bg-black/20 px-3 py-1 text-xs font-bold text-white/55">{x}</span>)}</div></div><div className="w-44 shrink-0 max-md:mt-5"><div className="mb-1 flex justify-between text-xs font-black text-white/50"><span>Trust</span><span>{trust}/100</span></div><Progress v={trust}/><div className="mb-1 mt-4 flex justify-between text-xs font-black text-white/50"><span>Confidence</span><span>{conf}%</span></div><Progress v={conf}/></div></div></Card>)}</div></section><section id="context" className="scroll-mt-28 grid gap-4 lg:grid-cols-[1fr_280px]"><Card className="p-6"><h2 className="text-2xl font-black">Missing context map</h2><p className="mt-2 text-white/55">The report found strong claims but weak operational detail. The largest evidence gaps are cost basis, sample size, and independent methodology.</p><div className="mt-6 grid gap-3 sm:grid-cols-3">{[['Cost basis',88],['Sample size',72],['Methodology',81]].map(([a,v]:any)=><div key={a} className="rounded-2xl border border-white/10 bg-black/20 p-4"><div className="mb-2 flex justify-between text-sm font-black"><span>{a}</span><span>{v}% gap</span></div><Progress v={v}/></div>)}</div></Card><Card className="p-6"><AlertTriangle className="text-primary"/><b className="mt-4 block text-lg">Primary concern</b><p className="mt-2 text-sm leading-6 text-white/55">Income proof appears before any falsifiable methodology, increasing persuasion risk.</p></Card></section><section id="techniques" className="scroll-mt-28"><h2 className="mb-3 text-2xl font-black">Manipulation techniques detected</h2><div className="grid gap-4 md:grid-cols-3">{tactics.map(([a,b,v]:any)=><Card key={a} className="p-5"><Zap className="text-primary" size={20}/><h3 className="mt-4 font-black">{a}</h3><p className="mt-2 min-h-16 text-sm leading-6 text-white/55">{b}</p><div className="mt-4"><div className="mb-1 flex justify-between text-xs font-black text-white/45"><span>Signal strength</span><span>{v}%</span></div><Progress v={v}/></div></Card>)}</div></section><section id="sources" className="scroll-mt-28"><h2 className="mb-3 text-2xl font-black">Source verification snapshot</h2><Card className="overflow-hidden p-0">{sources.map(([a,b,c])=><div key={a} className="grid gap-3 border-b border-white/10 p-5 last:border-b-0 md:grid-cols-[1fr_1.2fr_90px]"><b>{a}</b><p className="text-white/55">{b}</p><span className="rounded-full border border-white/10 bg-white/[.06] px-3 py-1 text-center text-xs font-black text-white/65">{c}</span></div>)}</Card></section><section id="timeline" className="scroll-mt-28"><h2 className="mb-3 text-2xl font-black">Analysis timeline</h2><Card className="p-6"><div className="space-y-5">{timeline.map(([time,label,body])=><div key={time} className="grid grid-cols-[70px_18px_1fr] gap-4"><b className="font-black text-primary">{time}</b><div className="relative"><span className="block size-3 rounded-full bg-primary shadow-[0_0_18px_rgba(231,255,71,.45)]"/><span className="absolute left-[5px] top-4 h-[calc(100%+12px)] w-px bg-white/10 last:hidden"/></div><div><b>{label}</b><p className="mt-1 text-sm text-white/55">{body}</p></div></div>)}</div></Card></section></>}</div><GlowWrap glow="bg-primary/[.10]"><aside className="sticky top-20 h-fit"><Card className="p-6"><div className="flex items-center justify-between"><b>Report Summary</b><Gauge className="text-primary" size={20}/></div><div className="my-7 grid place-items-center"><div className="relative grid size-44 place-items-center rounded-full bg-[conic-gradient(#E7FF47_0_31%,rgba(255,255,255,.10)_31%_100%)] p-3 shadow-[0_0_46px_rgba(231,255,71,.16)]"><div className="grid size-full place-items-center rounded-full bg-[#181818] text-center"><div><div className="text-5xl font-black">31</div><p className="text-xs font-black uppercase tracking-[.18em] text-white/40">Trust Score</p></div></div></div></div><div className="grid gap-3">{[['Risk level','High'],['Confidence','84%'],['Category','Technology'],['Claims checked','9']].map(([a,b])=><div key={a} className="flex items-center justify-between rounded-2xl border border-white/10 bg-black/20 p-3"><span className="text-sm font-bold text-white/48">{a}</span><b>{b}</b></div>)}</div><div className="mt-5 rounded-2xl border border-primary/20 bg-primary/[.08] p-4"><b className="text-primary">Recommendation</b><p className="mt-1 text-sm leading-6 text-white/58">Do not cite this video as reliable evidence without external financial records and source links.</p></div><Button onClick={()=>toast('Report saved')}><Save size={16}/> Save intelligence report</Button></Card></aside></GlowWrap></div></div>}
function VerificationReport({toast}:{toast:(m:string,t?:string)=>void}){const[open,setOpen]=useState('Claim Verification');const sections=['Claim Verification','Supporting Evidence','Contradictions','Credibility Score','Source Links'];return <><Title title="Verification Report" sub="Source-focused scan of extracted claims, evidence quality, and contradictions." action={<Button onClick={()=>toast('Report saved')}><Save size={16}/> Save Report</Button>}/><div className="grid gap-5 xl:grid-cols-[1fr_340px]"><main className="space-y-4"><Card className="overflow-hidden p-0"><div className="grid md:grid-cols-[260px_1fr]"><div className="grid min-h-44 place-items-center bg-[#181818] text-primary"><Shield size={34}/></div><div className="p-6"><p className="text-sm text-white/45">youtube.com/watch?v=... • 6/27/2026 • Technology</p><h2 className="mt-2 text-2xl font-black">Source verification report</h2><p className="mt-2 text-white/60">Claims were extracted and compared against credible so text-[48px]urce placeholders and contradiction signals.</p></div></div></Card>{sections.map((x,i)=><Card key={x} className="p-5"><button onClick={()=>setOpen(open===x?'':x)} className="flex w-full justify-between font-black">{x}<ChevronDown className={open===x?'rotate-180':''}/></button>{open===x&&<p className="mt-3 text-white/60">{i===0?'Four claims extracted. Two have weak support, one is disputed, and one needs more source context.':'Detailed evidence stays collapsed until needed so the report remains easy to scan.'}</p>}</Card>)}</main><Card className="h-fit p-6"><b>Verification Summary</b><div className="my-6 text-center"><div className="text-6xl font-black">62%</div><p className="text-sm text-white/45">Credibility score</p></div><div className="space-y-4"><div className="flex justify-between"><span>Status</span><Badge>Unverified</Badge></div><div className="flex justify-between"><span>Confidence</span><b>78%</b></div><div className="flex justify-between"><span>Claims checked</span><b>4</b></div></div><div className="mt-6 grid gap-2"><Button onClick={()=>toast('Report saved')}><Save size={16}/> Save</Button><Button variant="secondary"><Download size={16}/> Export Summary</Button></div></Card></div></>}
function Verification(){const[tab,setTab]=useState('All'),[drawer,setDrawer]=useState<any>(null),[exp,setExp]=useState(''),[sk,setSk]=useState(true);useEffect(()=>{setTimeout(()=>setSk(false),500)},[]);const claims=[['The presenter claims $50,000 in taxable profits.','Disputed',23,81],['The source is independently verified.','Verified',82,74],['AI growth method over 30 months.','Unverified',52,73],['Tap water contains hidden risks.','High Risk',28,79]];const shown=claims.filter(c=>tab==='All'||c[1]===tab);return <div className="relative"><div className="pointer-events-none absolute left-1/3 top-10 h-56 w-56 rounded-full bg-primary/[.055] blur-3xl"/><Title title="Source Verification" sub="Review claim credibility and supporting evidence."/><div className="mb-5 flex gap-2 flex-wrap">{['All','Verified','Disputed','Unverified','High Risk'].map(t=><button key={t} onClick={()=>setTab(t)} className={`rounded-full px-4 py-2 font-black ${tab===t?'bg-primary text-[#181818]':'border border-white/10 bg-white/[.06] text-white hover:bg-white/[.06]'}`}>{t}</button>)}</div>{sk?<div className="grid gap-4 xl:grid-cols-2"><Skeleton/><Skeleton/></div>:shown.length?<GlowWrap glow="bg-primary/[.08]"><div className="grid gap-4 xl:grid-cols-2">{shown.map(c=><Card className="p-5" key={c[0]}><button onClick={()=>setExp(exp===c[0]?'':c[0])} className="flex w-full justify-between gap-4 text-left"><b>{c[0]}</b><Badge>{c[1] as string}</Badge></button><div className="mt-4 grid grid-cols-2 gap-4"><p><span className="text-sm text-white/45">Credibility</span><br/><b className="text-2xl">{c[2]}/100</b></p><div><div className="mb-1 flex justify-between text-sm"><span>Confidence</span><b>{c[3]}%</b></div><Progress v={c[3] as number}/></div></div>{exp===c[0]&&<p className="mt-3 rounded-xl bg-white/[.06] p-3 text-sm text-white/60">Click evidence to inspect sources, contradictions, and model notes.</p>}<div className="mt-4"><Button variant="secondary" onClick={()=>setDrawer(c)}><Eye size={16}/> View Evidence</Button></div></Card>)}</div></GlowWrap>:<Card className="p-10 text-center"><Shield className="mx-auto text-white/35"/><b>No verified claims</b><p className="text-white/45">Switch tabs to inspect other claim states.</p></Card>}{drawer&&<div className="relative z-50"><div className="pointer-events-none fixed right-10 top-20 z-50 h-72 w-72 rounded-full bg-primary/[.08] blur-3xl"/><Drawer title="Evidence Drawer" onClose={()=>setDrawer(null)}><Badge>{drawer[1]}</Badge><h3 className="mt-4 text-xl font-black">{drawer[0]}</h3><div className="mt-5 space-y-4"><Card className="p-4"><b>Credibility</b><p>{drawer[2]}/100 • Confidence {drawer[3]}%</p></Card><Card className="p-4"><b>Supporting sources</b><p className="text-white/60">Low source support. Source links placeholder.</p></Card><Card className="p-4"><b>Contradictions</b><p className="text-white/60">No independent evidence; selective framing.</p></Card><Card className="p-4"><b>Evidence notes</b><p className="text-white/60">Model found persuasive language and missing methodology.</p></Card></div></Drawer></div>}</div>}
