function ThemeToggle({theme,setTheme}:{theme:'dark'|'light';setTheme:(t:'dark'|'light')=>void}){return <div className="theme-toggle fixed right-5 top-5 z-[70] flex items-center gap-1 rounded-2xl border p-1 backdrop-blur-xl"><button onClick={()=>setTheme('dark')} className={`inline-flex h-9 items-center gap-2 rounded-xl px-3 text-xs font-black ${theme==='dark'?'bg-primary text-[#181818]':'text-white/60'}`}><Moon size={15}/>Dark</button><button onClick={()=>setTheme('light')} className={`inline-flex h-9 items-center gap-2 rounded-xl px-3 text-xs font-black ${theme==='light'?'bg-primary text-[#181818]':'text-white/60'}`}><Sun size={15}/>Light</button></div>}
export default function App(){const[active,setActive]=useState<Page>('Dashboard'),[reports,setReports]=useState<Report[]>(seed),[toasts,setToasts]=useState<any[]>([]),[cmd,setCmd]=useState(false),[theme,setTheme]=useState<'dark'|'light'>('dark');const toast=(msg:string,type='success')=>{const id=Date.now();setToasts(t=>[...t,{id,msg,type}]);setTimeout(()=>setToasts(t=>t.filter(x=>x.id!==id)),2600)};useEffect(()=>{const f=(e:KeyboardEvent)=>{if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){e.preventDefault();setCmd(true)}};addEventListener('keydown',f);return()=>removeEventListener('keydown',f)},[]);const addReport=(r:Report)=>setReports(v=>[r,...v]);const common={setActive,reports,addReport,toast};const pages:Record<Page,ReactNode>={Dashboard:<Dashboard {...common}/>,Analyze:<Analyze {...common}/>,"Analysis Report":<Report toast={toast}/>,"Verification Report":<VerificationReport toast={toast}/>,History:<HistoryPage reports={reports} setActive={setActive}/>,Verification:<Verification/>,Feedback:<Feedback toast={toast}/>,Settings:<SettingsPage toast={toast} setReports={setReports}/>};return <div className={`theme-root ${theme==='light'?'theme-light':'theme-dark'} min-h-screen ${theme==='light'?'bg-[#F7F7F2] text-[#181818]':'bg-[#181818] text-white'} font-['Lato'] lg:pl-[76px]`}><ThemeStyles/><div className="theme-page-glow pointer-events-none fixed right-[-120px] top-[-120px] z-0 h-80 w-80 rounded-full blur-3xl"/><Sidebar active={active} setActive={setActive} openCmd={()=>setCmd(true)}/><ThemeToggle theme={theme} setTheme={setTheme}/><Toasts items={toasts}/>{cmd&&<Palette setActive={setActive} onClose={()=>setCmd(false)}/>}<main className="relative z-10 mx-auto max-w-[1360px] p-6 pt-20 lg:p-9 lg:pt-20">{pages[active]}</main></div>}